-- 1. Carpenters × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'web-design',
  'Carpentry is a craft where the finished product speaks for itself, and your website must let that work do the talking. Whether you specialise in bespoke fitted furniture, kitchen installations, timber framing, staircase construction, or general first and second fix carpentry, potential clients need to see the quality of your joinery before they make an enquiry. A homeowner commissioning a handmade oak staircase or a set of bespoke built-in wardrobes is investing in craftsmanship, and your website must communicate that level of skill through detailed project photography, close-up joinery details, and the story behind each piece. Most carpenter websites fail because they treat the work like a commodity rather than a craft. Generic stock photos of tools, a basic list of services, and a contact form do nothing to convey the difference between your bespoke work and a flat-pack alternative. A purpose-built website for a carpenter or joiner showcases the grain of the timber, the precision of the joints, and the transformation of raw materials into finished pieces. We build portfolio-centred websites that present your craftsmanship in the detail it deserves, with project galleries organised by type, close-up detail photography, and the material choices that define your work.',
  'Clients commissioning bespoke carpentry are choosing craftsmanship over mass production. They need to see evidence that you possess the skill they are paying a premium for. A website with low-quality photos or generic content fails to differentiate your handcrafted work from factory-produced alternatives. Your online portfolio is how discerning clients assess your capability before making contact, and the quality of its presentation must match the quality of your work.',
  'We design around the visual storytelling that carpentry demands. Project galleries feature high-resolution detail shots alongside full-room views. Material information panels explain timber choices and finishing techniques. Before-and-after sliders show transformations. Workshop and process photography adds authenticity by showing the craft behind the finished piece.',
  '[{"title": "Portfolio photography that fails to show joinery detail", "description": "A wide-angle photo of a fitted kitchen from across the room tells a prospect almost nothing about your craftsmanship. They cannot see the dovetail joints, the grain matching, the precision of the scribing, or the quality of the finish. Without close-up detail photography that reveals the skill in your work, your portfolio looks identical to every joiner using the same cabinet carcasses."}, {"title": "No differentiation between bespoke work and standard carpentry", "description": "A carpenter who builds bespoke staircases and hand-crafts fitted furniture needs a different web presence to one offering standard first and second fix. When your website lists all services equally, clients seeking premium bespoke work cannot distinguish you from general carpenters, and the premium pricing your craftsmanship commands feels unjustified."}, {"title": "Material and process information completely absent", "description": "Discerning clients choosing bespoke carpentry want to understand timber species, finishing techniques, and construction methods. A website that shows only finished photos without explaining the oak, walnut, or ash used, the hand-finished oils or lacquers applied, and the traditional joinery methods employed misses the opportunity to educate clients about the value of genuine craftsmanship."}]',
  '[{"title": "Craft-focused portfolio with detail photography", "description": "Project galleries featuring both room-context photography and close-up detail shots that reveal joinery quality, grain patterns, and finishing precision. Each project includes material specifications, timber species information, and construction technique notes that educate visitors about the craftsmanship behind each piece. This elevates your portfolio from a photo gallery to a showcase of skill."}, {"title": "Project categorisation by type and specialisation", "description": "Dedicated gallery sections for bespoke kitchens, fitted furniture, staircases, timber framing, doors and windows, and general carpentry. Visitors interested in a bespoke bookcase navigate directly to fitted furniture examples. Those needing a staircase find your staircase portfolio immediately. This categorisation helps prospects assess your specific experience with their project type."}, {"title": "Workshop and process content building craft authenticity", "description": "Photography and content showing your workshop, tools, and work in progress. The journey from raw timber through marking out, cutting, joinery, assembly, and finishing tells the story of craftsmanship that distinguishes bespoke carpentry from manufactured alternatives. This process transparency justifies premium pricing and attracts clients who value genuine handcrafted quality."}]',
  '[{"question": "How important is close-up photography for a carpenter''s website?", "answer": "Essential. Close-up detail shots are what differentiate bespoke carpentry from factory-produced alternatives. The precision of a dovetail joint, the seamless grain matching across panels, and the quality of a hand-applied finish are only visible in detailed photography. We advise on photographing your work to capture these craft details effectively."}, {"question": "Should I separate my bespoke work from general carpentry on the website?", "answer": "Yes, if you want to attract bespoke commissions. Clients seeking handcrafted fitted furniture or a bespoke staircase have different expectations and budgets to those needing standard first fix carpentry. Separate portfolio sections with distinct messaging ensure premium prospects find the evidence of craftsmanship they are looking for."}, {"question": "Can the website include information about timber species and techniques?", "answer": "Absolutely, and it should. Material and technique information serves two purposes: it educates clients about the value of your work, and it targets SEO terms like bespoke oak furniture or handmade walnut kitchen that discerning clients search for. Project pages that specify timber species, joinery methods, and finishing techniques attract higher-value enquiries."}, {"question": "How do I get good photos of my carpentry work?", "answer": "We can advise on smartphone photography techniques for workshop and on-site documentation. For portfolio pieces, we recommend professional photography of your best work. Even a half-day shoot of three or four completed projects provides enough high-quality imagery to populate a compelling portfolio. The investment in professional photos pays for itself through the quality of enquiries they generate."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Carpenters × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'seo',
  'The search landscape for carpentry spans a wide spectrum from commodity services to premium bespoke commissions, and your SEO strategy must target the right end of that spectrum for your business. Someone searching for carpenter near me might need a door hung or might want a handcrafted oak staircase. The value difference between these enquiries is enormous. Effective SEO for carpenters and joiners goes beyond generic terms to target the specific searches that represent your most valuable work: bespoke fitted wardrobes, handmade kitchen, oak staircase maker, bespoke bookcase joiner, and similar craft-specific terms. These searches come from clients who have already decided they want bespoke craftsmanship rather than off-the-shelf alternatives, making them pre-qualified for premium work. Beyond bespoke terms, local SEO captures the steady stream of general carpentry searches: carpenter Maidstone, joiner Canterbury, kitchen fitter Ashford. Our SEO campaigns for carpenters build visibility across both the premium bespoke market and the local general carpentry market, ensuring your business captures enquiries at every price point you serve.',
  'Bespoke carpentry searches have some of the highest client values in the trades. A single bespoke kitchen commission can be worth ten to thirty thousand pounds. Even general carpentry searches represent steady, profitable work. Without SEO, you rely entirely on word of mouth and repeat business, leaving the growing number of homeowners who search online to find and commission your competitors instead.',
  'We build SEO campaigns targeting both bespoke craft terms and local general carpentry searches. Bespoke content uses material-specific and technique-specific keywords: handmade oak furniture, bespoke walnut kitchen, traditional joinery. Local SEO targets geographic variations for general carpentry. Portfolio pages are optimised to rank for the specific project types they showcase.',
  '[{"title": "Invisible for bespoke and premium carpentry searches", "description": "When a homeowner searches for bespoke fitted wardrobes Kent or handmade oak staircase, they are seeking premium craftsmanship and are prepared to pay accordingly. These high-value searches are wasted on carpenters whose websites have no optimised content targeting these specific terms. Your finest work generates no online visibility because it is buried in a generic portfolio page."}, {"title": "Generic carpenter near me competing against all levels of the trade", "description": "Ranking for carpenter near me pits you against everyone from apprentice odd-job workers to master craftsmen. Without SEO that differentiates your positioning, you receive a mix of enquiries ranging from hanging a door to commissioning bespoke furniture, with no way for search engines to understand which end of the market you serve."}, {"title": "No portfolio content optimised for search visibility", "description": "Your portfolio contains beautiful examples of bespoke staircases, fitted libraries, and handcrafted kitchens, but the images have no descriptions, no alt text, no material information, and no location context. Google cannot index or rank visual content without supporting text. Your best work is invisible to search engines."}]',
  '[{"title": "Bespoke and craft-specific keyword targeting", "description": "Optimised content targeting the premium search terms that attract high-value commissions: bespoke fitted furniture, handmade kitchen, oak staircase maker, custom built-in wardrobes, and similar craft-specific queries. Each term has dedicated content with material-specific and technique-specific language that signals genuine craftsmanship to both search engines and discerning clients."}, {"title": "Portfolio SEO with optimised project pages", "description": "Each portfolio project becomes a search-optimised page with descriptive titles, detailed alt text on every image, material specifications, location references, and project narratives. A bespoke oak bookcase project in Canterbury becomes a page targeting bespoke bookcase Canterbury and oak fitted furniture Kent, capturing location-specific searches for years after the project is completed."}, {"title": "Local SEO for general carpentry coverage", "description": "Google Business Profile optimisation, local citation building, and location-specific landing pages targeting general carpentry searches across your service area. This captures the steady stream of local carpentry work, from kitchen fitting to door hanging, that provides reliable baseline revenue alongside premium bespoke commissions."}]',
  '[{"question": "Can SEO help me attract more bespoke carpentry commissions?", "answer": "Yes. Bespoke carpentry searches come from clients who have already decided they want handcrafted quality rather than off-the-shelf alternatives. By targeting these specific terms with optimised content that demonstrates your craft capabilities, you attract pre-qualified prospects who value craftsmanship and are prepared to pay premium prices."}, {"question": "Should I target generic carpenter terms or specialist terms?", "answer": "Both, but weighted towards your ideal work. If you want more bespoke furniture commissions, invest heavily in content targeting those terms. If general carpentry provides your bread-and-butter income, ensure local SEO covers your service area. The balance depends on where you want to grow, and we adjust the strategy accordingly."}, {"question": "How do I get my portfolio images to rank in Google?", "answer": "Images need descriptive file names, detailed alt text, surrounding context text, and structured data. A portfolio image labelled IMG_4521.jpg with no alt text is invisible to Google. The same image with the filename bespoke-oak-staircase-canterbury.jpg and detailed alt text describing the timber species and joinery becomes searchable and can rank in Google Images for relevant queries."}, {"question": "How competitive are bespoke carpentry search terms?", "answer": "Less competitive than generic trade terms, which is good news. While carpenter near me is highly competitive, bespoke fitted wardrobes Kent or handmade oak kitchen Canterbury have far fewer competitors targeting them deliberately. This means you can achieve strong rankings relatively quickly with focused content and optimisation, even against established competitors."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 3. Carpenters × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'lead-capture',
  'Carpentry enquiries range enormously in scope and value, from fitting a new internal door to commissioning a complete bespoke kitchen. The information needed to respond intelligently to each type is completely different, yet most carpenter websites funnel every enquiry through the same generic contact form. A homeowner describing a bespoke staircase vision in a message box provides nothing your team can work with. Without knowing the timber preference, style reference, number of treads, whether the staircase is straight or turning, and the budget range, your initial response is inevitably a generic reply requesting a site visit. Purpose-built lead capture for carpenters creates enquiry paths that match the specific type of work being requested. Bespoke furniture enquiries capture design inspiration, timber preferences, room dimensions, and budget range. Kitchen fitting enquiries ask about existing layout, new kitchen supplier, and specific requirements. General carpentry requests capture the scope of work needed. Each path collects enough information for an informed initial response that demonstrates your understanding of the project before you have even visited the property.',
  'Bespoke carpentry clients invest time imagining their project before making an enquiry. When they reach your website, they have design ideas, material preferences, and budget expectations. A generic contact form that reduces their vision to a two-line message wastes this context and forces a blind response. Capturing their project vision in a structured format lets you respond with genuine insight, differentiating your practice from competitors who reply with standard call-back messages.',
  'We build enquiry flows that reflect the different types of carpentry work. Bespoke commissions capture design references, timber preferences, dimensions, and budget. Kitchen fitting enquiries capture supplier details, unit specifications, and site conditions. General carpentry forms capture scope, quantity, and timeline. Each path ensures you receive the right information for an informed response.',
  '[{"title": "Bespoke project visions reduced to vague contact form messages", "description": "A client who has spent hours on Pinterest imagining their perfect bespoke bookcase submits a message saying I would like some shelving built please. The entire design vision they have developed is lost. Your response is generic because you have no idea whether they want floating shelves or a floor-to-ceiling fitted library. The opportunity to impress with an informed response is missed."}, {"title": "No way to assess project scope before committing to a site visit", "description": "Every carpentry enquiry currently requires a site visit before you can even determine whether the project is viable. You drive forty minutes to measure a room only to discover the client wants a simple shelf fitted, not the bespoke fitted furniture they vaguely described. Without pre-qualification, every enquiry costs you travel time before you know its value."}, {"title": "Inspiration images and design references not captured", "description": "Clients commissioning bespoke carpentry almost always have reference images: Pinterest boards, magazine tear-sheets, or photos of furniture they admire. These references are invaluable for understanding what the client wants. A contact form with no image upload capability forces clients to describe visual ideas in words, losing the information that would make your first conversation productive."}]',
  '[{"title": "Bespoke commission enquiry flow with design reference capture", "description": "Clients enquiring about bespoke furniture, staircases, or fitted pieces complete a flow that captures: project type, room dimensions, timber preference, style references, existing decor description, and budget range. An image upload area lets them share Pinterest images, magazine photos, or sketches. You receive a visual brief that lets you respond with an informed design perspective."}, {"title": "Service-specific forms for different carpentry categories", "description": "Separate enquiry paths for bespoke furniture commissions, kitchen fitting, staircase construction, timber framing, and general carpentry. Each captures the specific information relevant to that work type. Kitchen fitting asks about unit supplier and specification. General carpentry captures the scope and quantity of work. This ensures every enquiry arrives with the right context."}, {"title": "Project value assessment for prioritised follow-up", "description": "Enquiry responses are automatically assessed for project value based on scope, material preferences, and budget range. A bespoke oak kitchen commission is flagged for priority follow-up. A single door fitting is acknowledged but queued appropriately. This ensures your limited response time is invested in the opportunities that deliver the most value."}]',
  '[{"question": "How does capturing design inspiration images improve my response?", "answer": "When a client shares Pinterest images of oak bookcases with ladder rails, you can respond referencing similar projects you have completed, suggest the oak species and finish that would achieve their vision, and provide an informed budget indication. This demonstrates expertise and understanding that a generic callback message cannot match. The image upload makes every initial conversation more productive."}, {"question": "Will a detailed enquiry form deter casual enquiries?", "answer": "It will filter out enquiries from people who have not seriously considered their project, and that is beneficial. A homeowner with a genuine bespoke furniture commission welcomes a professional enquiry process. The form signals that you take a thorough, craft-focused approach. Prospects who abandon a detailed form were unlikely to convert into valuable projects."}, {"question": "Can the form help me quote more accurately before a site visit?", "answer": "Yes. With room dimensions, timber preferences, style references, and budget range captured in the enquiry, you can provide an informed ballpark indication before visiting. This sets realistic expectations early, ensures your site visit time is invested in viable projects, and positions you as a professional who prepares thoroughly rather than arriving blind."}, {"question": "How do you handle enquiries for general carpentry versus bespoke work?", "answer": "The initial question asks what type of carpentry is needed. General carpentry requests follow a simpler path capturing scope, quantity, location, and timeline. Bespoke commissions enter the detailed flow with material preferences, design references, and dimensional information. This ensures neither type of client is burdened with inappropriate questions."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 4. Carpenters × Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'business-automation',
  'Carpenters and joiners spend their days with timber, tools, and clients, not with spreadsheets and email. Yet running a carpentry business demands constant administrative attention: quotes need writing and following up, material orders need placing with timber merchants, invoices need raising and chasing, workshop schedules need coordinating, and client communications need managing throughout what can be multi-week bespoke projects. Most carpenters handle this administration in the evenings, sacrificing personal time after physically demanding days in the workshop or on site. Business automation for carpenters systematises every repeatable process in your business. Enquiry acknowledgements go out immediately. Quote follow-ups chase at defined intervals without you remembering to do so. Material lists trigger ordering reminders from your preferred timber merchants. Client progress updates are sent at agreed project milestones. Invoices are raised upon completion and payment reminders follow automatically. Each of these processes runs reliably in the background, giving you back the evenings currently consumed by administration and ensuring nothing slips through the cracks when you are absorbed in a complex piece of joinery.',
  'A carpenter absorbed in a complex dovetail joint or a precision staircase fitting should not be interrupted by administrative tasks that a system can handle. Every evening spent quoting, invoicing, and chasing emails represents lost personal time and reduced quality of life. Automation handles these predictable tasks with greater consistency than manual effort, ensuring your business runs professionally regardless of how busy your workshop or site commitments are.',
  'We automate around the carpentry project lifecycle. Enquiry flows capture project details and trigger acknowledgements. Quote templates pre-populate with standard pricing for common tasks. Material ordering reminders are triggered by project schedules. Progress update sequences keep clients informed during multi-week commissions. Invoicing and payment chasing run automatically upon completion.',
  '[{"title": "Quote follow-ups forgotten because you are in the workshop", "description": "You sent a detailed quote for a bespoke wardrobe commission two weeks ago. The client has not responded and you have forgotten to follow up because you have been absorbed in a staircase project in the workshop. The quote expires without a single follow-up, and the client instructs a competitor who chased more persistently. This pattern repeats monthly."}, {"title": "Material ordering delayed because project preparation competes with active work", "description": "You are starting a fitted kitchen installation next Monday but have not ordered the timber and ironmongery because this week was consumed by finishing the current project. A rush order to the timber merchant costs premium rates and risks delivery delays that push back the entire project start. Proactive ordering should happen automatically based on project schedules."}, {"title": "Clients anxious during multi-week bespoke projects due to silence", "description": "A client commissioning a bespoke fitted library expects updates on how their project is progressing. When they hear nothing for ten days while their furniture is being built in your workshop, anxiety builds. They call to check progress, interrupting your work. A simple automated update at agreed milestones would prevent the anxiety and the interruption."}]',
  '[{"title": "Automated enquiry and quote lifecycle management", "description": "New enquiries receive immediate acknowledgement with timeline expectations. When you send a quote, the system schedules follow-up reminders at intervals you define: a check-in after five days, a gentle follow-up after ten days, and a final prompt after three weeks. Accepted quotes automatically trigger project setup sequences including material ordering reminders and client welcome information."}, {"title": "Project milestone communications for bespoke commissions", "description": "Multi-week bespoke projects are divided into communication milestones: design finalisation, material procurement, construction start, key assembly stages, finishing, and delivery or installation. At each milestone, the client receives a branded update with progress information and next-stage details. This keeps clients informed and confident without requiring you to write individual update emails."}, {"title": "Automated invoicing and payment collection", "description": "Project completion triggers automatic invoice generation using your agreed pricing. For staged projects, milestone completions generate the corresponding staged invoice. Payment reminders follow at defined intervals if payment is not received. Direct payment links in invoices and reminders make it easy for clients to pay immediately, improving your cash flow without manual chasing."}]',
  '[{"question": "Can automation handle the variety of carpentry projects I do?", "answer": "Yes. We create different workflow templates for different project types. A bespoke furniture commission follows a multi-week workflow with design, procurement, construction, and installation stages. A kitchen fitting follows a shorter workflow with survey, installation, and snagging stages. General carpentry tasks use a simple quote-schedule-complete-invoice flow. Each template is tailored to the project type."}, {"question": "How do automated client updates work for workshop-based projects?", "answer": "You define the milestones for each project type. When you log that a milestone is reached, such as timber selected and ordered, frame construction complete, or finishing underway, the system sends the client a branded update email. You can attach a workshop photo to show progress. Clients feel involved in the creation of their bespoke piece without you writing detailed emails."}, {"question": "Can it remind me to order materials from my timber merchant?", "answer": "Yes. When a project is confirmed and scheduled, the system calculates the ordering date based on your lead time requirements and triggers a reminder. For standard materials, it can generate an order list based on the project specification. This ensures materials arrive before the project start date without relying on your memory during busy workshop periods."}, {"question": "Will automation help me chase outstanding payments?", "answer": "Absolutely. Invoices are generated automatically upon project completion or at agreed milestones. If payment is not received within your terms, the system sends a polite reminder at seven days, a firmer follow-up at fourteen days, and a final notice at twenty-eight days. Payment links in every communication make it easy for clients to pay immediately."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 5. Carpenters × Branding
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'branding',
  'Carpentry branding must reflect the craft itself: considered, precise, and made from quality materials. A carpenter''s brand should feel as carefully constructed as their joinery. Yet most carpenters either have no deliberate branding at all, relying on their name in plain text on a van and business card, or have a generic logo that could belong to any trade. The branding opportunity for carpenters and joiners is distinctive because the craft has such strong visual and material associations. Timber grain textures, tool silhouettes, workshop imagery, and the warm tones of natural wood provide a rich design vocabulary that is unique to the trade. A well-crafted carpenter brand communicates the attention to detail and quality of workmanship that clients expect, before they have even seen a portfolio piece. Your brand appears on your van when parked outside a client''s home during an installation, on the label inside a bespoke piece of furniture, on the quotation that arrives in a client''s inbox, and on every piece of communication your business produces. We develop carpenter brands that honour the craft tradition whilst presenting a contemporary, professional identity appropriate for the premium market where bespoke carpentry commands its highest fees.',
  'Bespoke carpentry commands premium pricing, and premium pricing requires premium brand perception. A homeowner commissioning a five-thousand-pound fitted bookcase expects the carpenter to present professionally at every touchpoint. A handwritten quote on a scrap of paper, an unbranded van, and a basic text-only email address undermine the premium positioning that your craftsmanship deserves. Brand presentation must match the quality of the work.',
  'We develop carpenter brands drawing on the visual language of the craft: timber textures, grain patterns, tool forms, and workshop aesthetics. The brand extends to practical applications specific to carpentry: van livery, workshop signage, furniture labels and maker''s marks, quotation templates, and portfolio presentation materials. Every element reflects the precision and quality of the craft.',
  '[{"title": "No visual identity beyond a name in plain text", "description": "Many carpenters operate with their name set in a standard font on a plain business card and an unbranded van. This absence of visual identity makes the business indistinguishable from any other sole trader. When a client compares your plain-text quote to a competitor''s professionally branded proposal, the visual impression influences their perception of which carpenter is more established and capable."}, {"title": "Branding that does not reflect the quality of the craftsmanship", "description": "A carpenter producing exquisite bespoke furniture with a cheap-looking logo and inconsistent presentation creates a disconnect. The brand suggests budget work whilst the portfolio demonstrates premium craftsmanship. This inconsistency confuses prospects who expect brand presentation to reflect the standard of work, and may deter the premium clients your work deserves."}, {"title": "No maker''s mark or furniture labelling for completed pieces", "description": "Bespoke furniture craftsmen throughout history have signed their work with maker''s marks. A fitted kitchen, a handmade desk, or a bespoke wardrobe that carries your branded maker''s label becomes a permanent, daily advertisement for your craftsmanship. Without a label, your work is anonymous and generates no ongoing recognition or referrals from visitors who admire it."}]',
  '[{"title": "Craft-inspired brand identity with premium positioning", "description": "A distinctive brand identity drawing on the visual language of carpentry and joinery. Logo design, colour palette, and typography reflect the warmth, precision, and natural quality of timber craft. The identity positions your business at the premium end of the market where bespoke commissions command the fees your skill deserves."}, {"title": "Maker''s mark and furniture labelling system", "description": "A branded maker''s mark designed for application inside or on completed bespoke pieces. Engraved brass plaques, embossed leather labels, or branded timber blocks that identify your work permanently. Every bespoke piece becomes a lasting advertisement for your craftsmanship, generating recognition and referrals from everyone who sees and admires it."}, {"title": "Complete business collateral reflecting craft quality", "description": "Branded quotation templates, business cards, portfolio presentation materials, and van livery all designed to the same standard of quality and attention to detail that defines your carpentry. When a client receives your branded quotation, it communicates the same precision and care they will see in the finished piece."}]',
  '[{"question": "How do you create a brand that reflects carpentry as a craft?", "answer": "We draw on the visual associations unique to carpentry: timber grain textures, the warmth of natural wood tones, the precision of joinery details, and the heritage of the craft tradition. The resulting brand feels authentic to the trade rather than generic. Colour palettes, textures, and design elements all reference the materials and processes that define your work."}, {"question": "What is a maker''s mark and how does it help my business?", "answer": "A maker''s mark is a branded label applied to completed bespoke pieces: an engraved plaque inside a fitted wardrobe, a branded label under a bespoke table, or a discreet stamp inside a handmade cabinet. It identifies your work permanently, so every visitor who admires the piece knows who made it. This generates ongoing referrals from work completed years ago."}, {"question": "Can you design my van livery to match the craft brand?", "answer": "Yes. Van livery is designed as part of the brand suite, using the same visual language applied to your vehicle. For carpenters, this often means a more refined, craft-focused aesthetic than typical trade van graphics. The design communicates quality and precision when your van is parked outside a client''s property during an installation."}, {"question": "Should a carpenter''s brand look traditional or modern?", "answer": "It depends on your market position. A carpenter specialising in period restoration may benefit from heritage-inspired branding. One creating contemporary bespoke furniture needs a modern aesthetic. Most carpenters benefit from a design that honours the craft tradition whilst presenting a contemporary, professional identity. We find the right balance during the discovery process."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 6. Carpenters × Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'social-media-setup',
  'Carpentry is one of the most naturally engaging trades on social media. Videos of hand-cut joints, time-lapses of furniture taking shape from raw timber, and the satisfying reveal of a completed bespoke piece generate genuine fascination that few other professions can match. The process of transforming rough-sawn boards into a finished piece of furniture or a precision-fitted staircase is inherently compelling content. Yet most carpenters do not capitalise on this because they either ignore social media or post the occasional finished photo with no consistency or strategy. A properly set up social media presence for a carpenter turns every workshop day into content. Instagram becomes a visual portfolio that updates with every project, attracting followers who are future clients. Facebook connects you with local homeowners seeking recommendations. YouTube and TikTok reach audiences who discover your craftsmanship through process videos and are compelled to enquire when they have a project. We set up your profiles with professional branding, content categories optimised for each platform, and posting frameworks that make consistent content creation achievable alongside a full workshop schedule.',
  'Carpentry process content consistently outperforms most other trade content on social media because people find the transformation of raw materials into finished objects genuinely captivating. A time-lapse of a bespoke kitchen installation or a close-up of hand-cut dovetails attracts thousands of views and positions you as a skilled craftsman in the minds of future clients. This organic reach is marketing you cannot buy.',
  'We set up social profiles optimised for visual craft content. Instagram is structured as a portfolio and process showcase with Reels templates for workshop videos. Facebook is configured for local community engagement and recommendations. Content categories include workshop process, project reveals, material features, and technique demonstrations.',
  '[{"title": "Compelling workshop content never reaching potential clients", "description": "Every day in your workshop produces content that social media audiences love: the first cut on a new piece of oak, a stack of dovetail joints being tested, the assembly of a bespoke frame. This compelling visual material goes undocumented and unseen. Competitors who post similar content attract followers, enquiries, and the reputation for craftsmanship that your equal or superior work also deserves."}, {"title": "No Instagram presence despite the platform being ideal for visual trades", "description": "Instagram is the natural home for carpentry content. The platform rewards beautiful imagery, process videos, and satisfying transformations. A carpenter without an Instagram presence misses the audience that is most likely to commission bespoke work: homeowners with aesthetic sensibilities who discover craftspeople through visual platforms."}, {"title": "Finished project photos only, with no process content", "description": "Posting only completed project photos misses the engagement opportunity of the making process. A finished bookcase photo gets modest engagement. A Reel showing that bookcase being built from raw timber through to final installation gets ten times the views. Without process content, you are showing only the outcome and missing the storytelling that builds an audience."}]',
  '[{"title": "Instagram portfolio and workshop showcase setup", "description": "A professional Instagram profile configured as a visual portfolio with highlighted story categories for different project types, workshop processes, and material features. Reel templates for common workshop content: time-lapse construction, joint cutting, finishing application, and project reveals. Bio and profile optimised for discoverability by homeowners searching for bespoke carpentry."}, {"title": "Facebook community engagement and referral configuration", "description": "A complete Facebook business page with branded imagery, service descriptions, portfolio highlights, and review collection setup. Configuration for local community engagement including strategies for responding to carpenter recommendation requests in local groups. Facebook is positioned as your local reputation and referral platform."}, {"title": "Content framework for sustainable workshop documentation", "description": "A structured approach to documenting your daily work for social media: quick phone clips of key moments, a weekly project progress post, a monthly completed project reveal, and ongoing material and technique features. Posting templates and scheduling guidance make consistent content creation achievable in ten to fifteen minutes per day."}]',
  '[{"question": "What kind of carpentry content performs best on social media?", "answer": "Process content consistently outperforms finished project photos. A fifteen-second Reel showing dovetails being cut and fitted, a time-lapse of a kitchen installation, or a before-and-after transformation generates significantly more engagement and reach. The making process is inherently satisfying to watch, and this fascination translates into followers and future enquiries."}, {"question": "How much time does social media take for a busy carpenter?", "answer": "With our content framework, ten to fifteen minutes per day. Capture a few quick clips during your working day using your phone. Spend ten minutes in the evening creating one or two posts using the templates. The key insight is that your daily workshop activity is the content. You are not creating content separately from your work; you are documenting the work you are already doing."}, {"question": "Should I show my techniques and processes, or keep them private?", "answer": "Show them. Demonstrating your skill is the most powerful marketing available to you. A video showing hand-cut dovetails does not teach someone to replicate your craftsmanship, but it demonstrates your capability to every viewer. The clients who commission bespoke work want to see evidence of skill, and process content provides that evidence compellingly."}, {"question": "Can social media generate bespoke carpentry commissions?", "answer": "Yes. Carpenters with active Instagram profiles report direct message enquiries from people who have been following their work and are ready to commission a piece. The visual nature of social media is perfectly suited to showcasing craftsmanship, and followers who engage with your content over months become pre-sold on your capability before they ever make contact."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 7. Carpenters × Digital Marketing
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'digital-marketing',
  'Digital marketing for carpenters must bridge two distinct markets: the premium bespoke commission market where clients seek specific craftsmanship, and the local general carpentry market where clients need reliable tradespeople for standard work. Each market requires different messaging, different channels, and different conversion approaches. Bespoke clients discover carpenters through Instagram portfolios, Google searches for specific furniture types, and recommendations from interior designers. General carpentry clients search locally, ask in Facebook groups, and respond to Google Ads. An effective digital marketing strategy for a carpentry business addresses both markets simultaneously, building your reputation as a skilled craftsman in the premium market whilst maintaining local visibility for the steady general work that provides baseline revenue. This requires a coordinated approach across search, social, and content channels, with each channel playing a specific role in reaching and converting each audience segment.',
  'Carpenters who rely solely on word of mouth limit their market to the network of people who already know them. Digital marketing expands your reach to every homeowner, interior designer, and property developer in your area who is searching for carpentry services online. For bespoke work, it reaches the clients who would never find you through local word of mouth because they search online for specific craft skills.',
  'We structure campaigns around the two distinct carpentry markets. Premium bespoke marketing uses Instagram, portfolio content, and craft-specific Google Ads targeting furniture types and material searches. Local general carpentry marketing uses Google Business Profile, local SEO, and community Facebook engagement. Each market receives appropriate messaging and budget allocation.',
  '[{"title": "Marketing that only reaches one segment of your market", "description": "Your Facebook page generates general carpentry enquiries but no bespoke commissions. Or your Instagram attracts admirers of your craft but no local door-fitting work. Without a strategy addressing both market segments, you either miss the premium commissions that justify your skill or lack the steady general work that provides reliable income."}, {"title": "No relationship with interior designers and specifiers", "description": "Interior designers, architects, and property developers are among the most valuable referral sources for bespoke carpenters. They commission repeatedly and refer high-value projects. Without digital marketing that positions you as a credible bespoke craftsman in their professional networks, these specifier relationships go to competitors with stronger online portfolios."}, {"title": "Inconsistent enquiry volume with no pipeline visibility", "description": "This month you have four projects. Next month you have one. The following month you are panicking about an empty workshop. Without marketing that generates a consistent pipeline of enquiries, your workload fluctuates unpredictably, making it impossible to plan capacity, commit to delivery dates, or maintain stable income."}]',
  '[{"title": "Dual-market campaign structure", "description": "Separate campaign streams for bespoke commissions and general carpentry. Bespoke campaigns run on Instagram and Google targeting craft-specific searches, with portfolio content showcasing your finest work. General carpentry campaigns focus on local Google visibility, community Facebook engagement, and Google Ads for service-specific searches. Each stream has its own messaging, targeting, and budget."}, {"title": "Portfolio marketing targeting specifiers and premium clients", "description": "Instagram portfolio content, targeted at interior designers and affluent homeowners, showcases your best bespoke work with material details and craft process content. Retargeting ensures portfolio visitors continue seeing your work during their decision-making process. Email outreach to local interior designers and architects introduces your capability with digital portfolio links."}, {"title": "Local visibility campaign for steady general carpentry work", "description": "Google Business Profile optimisation, local SEO for carpenter and joiner searches across your service area, and community Facebook engagement generating recommendations. Google Ads target specific general carpentry searches: kitchen fitter, door fitting, built-in wardrobe installation, and similar service terms. This ensures a steady baseline of general work alongside premium commissions."}]',
  '[{"question": "How should I split my marketing budget between bespoke and general work?", "answer": "It depends on your business goals. If you want to transition more towards bespoke commissions, invest sixty to seventy percent of budget in portfolio marketing and craft-specific advertising. If general carpentry provides essential baseline income, maintain fifty percent on local visibility. We adjust the balance as your business evolves and your bespoke reputation grows."}, {"question": "Can digital marketing help me connect with interior designers?", "answer": "Yes. A strong Instagram portfolio is often the first place interior designers look when sourcing craftspeople. Targeted outreach via email and LinkedIn introduces your capability with portfolio links. Google Ads targeting searches like bespoke furniture maker Kent put you in front of designers researching craftsmen for client projects."}, {"question": "How do I market bespoke carpentry when every project is unique?", "answer": "Through process and portfolio content that demonstrates your capability rather than selling a specific product. Each completed bespoke piece becomes marketing content that attracts similar commissions. Craft process videos demonstrate your skill. Material features showcase your timber knowledge. The combination positions you as a craftsman who can realise any bespoke vision."}, {"question": "Is Instagram really worth the time for a carpenter?", "answer": "For bespoke work, Instagram is the most effective marketing channel available. The platform is designed for visual content, and carpentry process and portfolio content performs exceptionally well. Carpenters with consistent Instagram presence report that it is their primary source of bespoke commissions. For general carpentry, Facebook and Google are more effective, which is why both channels are important."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 8. Carpenters × Workwear & Print
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'workwear-print',
  'Print and branded materials for carpenters occupy a unique space between trade functionality and craft presentation. Your printed materials must serve the practical needs of a working trade whilst reflecting the quality and precision that defines your carpentry. A quotation pack for a bespoke kitchen commission, a business card exchanged at a client''s home, and the label fitted inside a completed piece of furniture all represent your brand in moments that influence whether a prospect becomes a client and whether a completed piece generates future referrals. Carpentry businesses also benefit from workshop signage that impresses visiting clients, van livery that advertises the craft as you drive between installations, and branded workwear that identifies you professionally when working in clients'' homes. The materials specific to carpentry include furniture labels, workshop display photography, sample presentation materials, and project proposal documents that convey the bespoke nature of your commissions. We produce the complete range of physical brand materials a carpentry business needs, from maker''s marks to quotation templates, designed to the same standard of quality your clients expect from your joinery.',
  'Carpenters working in clients'' homes are their own most visible marketing. Your appearance, your van, your business card, and the documents you leave behind all contribute to the client''s impression of your professionalism. For bespoke commissions commanding premium prices, every touchpoint must reflect the quality standard you deliver. Professionally branded materials signal that you invest in your business presentation as carefully as you craft your joinery.',
  'We produce materials designed for the specific needs of carpentry businesses. Maker''s marks and furniture labels use premium materials appropriate for application to fine furniture. Quotation and proposal templates present bespoke commissions with the gravity they deserve. Workshop signage impresses visiting clients. Van livery communicates craft rather than commodity.',
  '[{"title": "Quotation documents that undermine premium pricing", "description": "A bespoke staircase quotation for eight thousand pounds delivered on a plain A4 sheet with no branding undermines the premium positioning. When the same quote is presented in a professionally designed proposal document with project visualisation, material specification, and branded presentation, the price feels justified by the professionalism of the entire package."}, {"title": "No furniture labels identifying completed bespoke work", "description": "A handcrafted bookcase installed in a client''s home will be seen by every visitor for decades. Without a maker''s mark or furniture label, nobody who admires the piece knows who made it. The referral potential of every bespoke commission is wasted because your work is anonymous once you leave the property."}, {"title": "Workshop appearing unprofessional when clients visit", "description": "Clients commissioning bespoke carpentry often visit the workshop to see work in progress and discuss design details. A workshop with no signage, no branded presentation, and no evidence of professional identity fails to reinforce the premium impression you want clients to take away. Workshop branding creates an environment that impresses and reassures visiting clients."}]',
  '[{"title": "Premium proposal and quotation document suite", "description": "Professionally designed quotation templates for bespoke commissions that present project scope, material specifications, design references, timeline, and pricing in a format befitting the premium nature of the work. For larger commissions, multi-page proposal documents with mood boards, material samples references, and detailed scope descriptions create a presentation that justifies premium pricing."}, {"title": "Maker''s marks and furniture labelling", "description": "Branded labels designed for permanent application to completed bespoke pieces. Options include engraved brass plaques, embossed leather labels, branded timber blocks, and adhesive labels suited to different applications. Each label carries your brand, contact details, and optionally the date and timber species, creating a permanent identification that generates referrals for years."}, {"title": "Workshop and van branding for craft businesses", "description": "Workshop signage that creates a professional environment for client visits, including entrance signage, portfolio display areas, and branded information boards. Van livery designed to communicate craftsmanship rather than generic trade services. The visual quality of every physical brand element matches the standard of the carpentry you produce."}]',
  '[{"question": "What material options are available for furniture labels?", "answer": "We offer engraved brass plaques in various sizes, embossed natural leather labels, laser-cut timber blocks in matching species to the piece, and high-quality adhesive labels with your brand design. The choice depends on the furniture type and your brand aesthetic. Brass plaques suit premium fitted furniture. Leather labels work beautifully on chairs and tables. Timber blocks are ideal for rustic or workshop-style pieces."}, {"question": "How should a bespoke carpentry quotation be presented?", "answer": "A bespoke commission quotation should be presented as a branded proposal document, not a plain price list. Include the project brief, material specifications with timber species and finish details, design references or sketches, build timeline, and clear pricing breakdown. This presentation justifies premium pricing and demonstrates the thoroughness of your approach."}, {"question": "Is van livery worthwhile for a carpenter?", "answer": "Yes, particularly if you install work in clients'' homes. Your van parked in a residential street during an installation is seen by every neighbour. Professional livery communicating bespoke carpentry or fine joinery attracts attention from homeowners who may be considering commissioning similar work. The cost of livery is typically recovered through a single additional enquiry."}, {"question": "Can you create branded sample presentation materials?", "answer": "Yes. If you present timber samples, finish options, or hardware choices to clients during consultations, we can create a branded sample box or portfolio system. Timber samples with printed labels identifying species and finish, presented in a branded case, create a professional consultation experience that reinforces your attention to detail."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 9. Carpenters × AI Chatbots
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'ai-chatbots',
  'Carpenters and joiners work with their hands, and those hands cannot hold a phone whilst operating a table saw, fitting a mortice lock, or installing kitchen cabinets. Enquiries that arrive during workshop hours go unanswered for hours, sometimes days. Meanwhile, the homeowner who submitted the enquiry has already contacted two other carpenters and is forming impressions based on who responds first and most helpfully. An AI chatbot on your carpentry website handles the initial conversation that you cannot: asking about the type of work needed, whether it is bespoke or standard, capturing dimensions and material preferences, collecting inspiration images, and qualifying whether the enquiry matches your specialisms and service area. For bespoke enquiries, the chatbot asks detailed questions about the project vision: what room is the piece for, what timber do they prefer, do they have inspiration images, and what is their budget range. For general carpentry, it captures the scope: how many doors, what type of kitchen units, and what is the timeline. Every answered question saves you time in the evening and ensures the prospect feels their enquiry is being handled professionally.',
  'The carpenter who answers enquiries fastest and most helpfully wins the work. When you are in the workshop or on an installation, you simply cannot respond. A chatbot bridges this gap by providing immediate, intelligent responses that capture project details and set expectations. Prospects feel their enquiry is valued and their project details are being taken seriously, even though you will not personally review the brief until the working day ends.',
  'We train the chatbot on carpentry-specific qualification: bespoke versus standard work, timber species preferences, joinery style questions, project type identification, and measurement capture. For bespoke enquiries, the bot asks about design vision and inspiration. For kitchen fitting, it asks about unit supplier and specification. Each conversation path reflects the actual information a carpenter needs.',
  '[{"title": "Bespoke enquiries going unanswered during workshop hours", "description": "A homeowner ready to commission a fitted home office submits an enquiry at 10am. You are in the workshop routing timber and do not see the message until 6pm. By then, the client has had a detailed conversation with a competitor''s chatbot, shared their design vision, and felt heard. Your evening reply feels late and generic by comparison."}, {"title": "Initial conversations consuming entire evenings", "description": "Every new enquiry requires the same initial conversation: what do you need, what room is it for, do you have preferences on timber, when do you need it by, what is your budget. These qualification conversations take fifteen to twenty minutes each. Three new enquiries in a week means an hour of your evening spent on repetitive question-and-answer before you can even assess the projects."}, {"title": "No way to distinguish bespoke commissions from basic requests", "description": "A message saying I need some carpentry work done could be a five-hundred-pound door-fitting job or a fifteen-thousand-pound bespoke kitchen commission. Without pre-qualification, both receive the same response and the same time investment. The bespoke client deserves a premium response, but you cannot provide one without knowing what they need."}]',
  '[{"title": "Bespoke project qualification with design vision capture", "description": "For bespoke enquiries, the chatbot walks the prospect through a design conversation: project type, room and space details, timber preferences, style inspiration, functional requirements, and budget range. An image upload option captures Pinterest references and inspiration photos. The result is a comprehensive design brief that lets you respond with informed craft perspective."}, {"title": "General carpentry scope capture with smart routing", "description": "For standard carpentry requests, the chatbot efficiently captures what is needed: door fitting, kitchen installation, shelving, flooring, or other work. Quantity, dimensions where applicable, material preferences, and timeline are collected. Enquiries are categorised by type and value, ensuring your response time reflects the project importance."}, {"title": "Material and technique information for informed prospects", "description": "The chatbot provides information about timber species you work with, joinery techniques you specialise in, and typical project timelines. Prospects researching bespoke carpentry receive helpful, knowledgeable responses that position your business as expert and approachable, building trust before the first human conversation."}]',
  '[{"question": "Can the chatbot discuss different timber species with prospects?", "answer": "Yes. We train the chatbot on the timber species you commonly work with: oak, walnut, ash, cherry, maple, and others relevant to your practice. It can describe the characteristics, colour, and typical applications of each species, helping prospects understand their options. For detailed timber selection, it directs to a consultation with you where species can be discussed with physical samples."}, {"question": "How does the chatbot handle bespoke design conversations?", "answer": "It follows a structured conversation flow: first identifying the project type, then asking about the space and dimensions, followed by timber and style preferences, functional requirements, and budget. An image upload option captures design inspiration. This is not a creative design consultation but a thorough brief capture that gives you everything needed for an informed initial response."}, {"question": "Will prospects feel comfortable sharing their project ideas with a chatbot?", "answer": "Yes. The chatbot presents as a project enquiry assistant, asking the same questions you would ask in a first phone call. Prospects appreciate the structured approach because it signals professionalism and thoroughness. The ability to share inspiration images and describe their vision in their own time, without time pressure, often produces more detailed briefs than phone conversations."}, {"question": "How does the handover work when I review the brief?", "answer": "The chatbot compiles all captured information into a structured project brief: project type, specifications, material preferences, inspiration images, budget range, and contact details. This is delivered to your email or preferred system. You review the brief, assess the project, and respond with a personalised message informed by the full context of their requirements."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 10. Carpenters × AI Content
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'ai-content',
  'Content marketing for carpenters taps into a deep public fascination with craftsmanship and the transformation of raw materials into beautiful, functional objects. Homeowners planning bespoke carpentry projects actively search for information: fitted wardrobe ideas, oak kitchen cost, bespoke bookcase designs, and built-in storage solutions are among the most searched terms by your target audience. Carpenters who publish content addressing these searches attract prospects who are actively planning commissions. But carpenters are makers, not writers. Your expertise lives in your hands and your workshop, not on a keyboard. The prospect of sitting down after a physical day of work to write a two-thousand-word guide about timber species or fitted furniture options is unappealing and unrealistic. AI content generation for carpenters produces well-structured first drafts covering material guides, project planning information, cost expectations, and design inspiration that you can review and enhance with your craft knowledge. Instead of never writing the article about choosing between oak and walnut for a bespoke kitchen, you spend fifteen minutes reviewing a draft and adding the practical insights that only a working carpenter can provide.',
  'Homeowners commissioning bespoke carpentry research extensively before choosing a craftsman. They search for material comparisons, design ideas, cost expectations, and process information. The carpenter who provides this information online is the one they contact first, because they have already demonstrated the knowledge and expertise the client is seeking. Without content, your craft expertise generates no online visibility.',
  'We generate content around the specific topics bespoke carpentry clients research. Material comparison guides cover the timber species you work with. Project planning content addresses the questions clients ask about commissions. Design inspiration content targets the visual searches that precede bespoke enquiries. All drafts require your craft review for authenticity.',
  '[{"title": "Decades of craft knowledge generating zero online visibility", "description": "You know the working properties of every timber species, the right joinery method for every application, and the realistic costs and timelines for bespoke commissions. This knowledge is exactly what your prospects search for online. But it exists only in your head and your workshop, invisible to the thousands of homeowners who search Google for the information you could provide."}, {"title": "Competitors'' content capturing your potential clients", "description": "Other carpenters and furniture companies have published guides about fitted wardrobes, bespoke kitchen costs, and timber selection. When homeowners find this content, those businesses become their first choice. Every month without content, your competitors'' advantage grows as their articles accumulate search rankings and your expertise remains unpublished."}, {"title": "Project case studies that showcase your best work never written", "description": "Every completed bespoke commission is a potential case study targeting location-specific searches. A handmade kitchen in Canterbury, a bespoke staircase in Maidstone, a fitted library in Sevenoaks. Each could attract local search traffic for years. But documenting these projects in a format suitable for web publication feels too time-consuming after the physical work of actually building them."}]',
  '[{"title": "Material and technique guides showcasing craft expertise", "description": "AI-generated guides comparing timber species, explaining joinery techniques, and discussing finishing options. Oak versus walnut, dovetails versus finger joints, oil versus lacquer finish. Your review adds the practical insights from years of working with these materials. The result is authoritative content that positions you as a knowledgeable craftsman and targets the material-specific searches your clients make."}, {"title": "Bespoke project planning content for commissioning clients", "description": "Guides addressing the questions clients ask before commissioning bespoke work: what to expect from the process, how to brief a carpenter effectively, realistic cost factors, timber selection guidance, and care instructions for handmade furniture. This content captures prospects at the planning stage and builds their confidence in commissioning you."}, {"title": "Project case studies optimised for local search visibility", "description": "For each completed bespoke project, AI generates a structured case study from your project details: timber species used, design brief, construction approach, and installation context. Location-specific optimisation targets searches like bespoke carpenter Canterbury or handmade furniture Maidstone. You review and enhance with the craft perspective that makes each case study authentic."}]',
  '[{"question": "Can AI write accurately about different timber species?", "answer": "AI produces well-researched drafts covering timber characteristics, working properties, and typical applications. Your review adds the practical nuance from years of experience: how oak behaves differently depending on the cut, how walnut responds to certain finishes, or why ash is your preferred choice for certain applications. This combination of research and craft experience creates the most valuable content."}, {"question": "How do I turn my completed projects into case study content?", "answer": "You provide the project details: what was built, which timber was used, any particular design challenges, the location, and photographs. AI generates a structured case study draft with a project narrative, material details, and design context. You review and add the construction insights that only the maker can provide. The process takes fifteen to twenty minutes per project."}, {"question": "Will content marketing really generate bespoke commissions?", "answer": "Yes. Homeowners planning bespoke furniture or fitted carpentry research extensively online before contacting a craftsman. Content that addresses their questions positions you as knowledgeable and trustworthy. A guide about choosing timber for a bespoke kitchen attracts exactly the client who is about to commission one. The traffic is highly targeted and commercially valuable."}, {"question": "How often should a carpenter publish new content?", "answer": "Two to three pieces per month is effective and sustainable with AI drafting. A mix of material or technique guides, project planning content, and completed project case studies builds organic visibility steadily. With your review taking fifteen minutes per piece, this represents less than an hour per week for content that generates enquiries for months and years."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 11. Carpenters × AI Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'carpenters',
  'ai-automation',
  'AI automation for carpentry businesses introduces intelligent systems that go beyond simple scheduled reminders to actively assist with the unique challenges of running a bespoke craft business. Traditional automation sends a fixed email on a fixed date. AI automation can process enquiry messages to categorise them by project type and value, draft initial responses tailored to the specific carpentry work requested, generate material cutting lists from project specifications, create procurement reminders based on workshop schedules, and produce client communications that reference the actual stage of their bespoke commission. For a carpenter juggling multiple bespoke projects with different timelines, material requirements, and client expectations, AI automation acts as an intelligent workshop coordinator. It ensures timber orders are placed with appropriate lead times for exotic species, client updates reference the correct project stage, invoicing follows commission milestones, and follow-up communications maintain the relationship after installation. This is not replacing your craftsmanship or design decisions. It is handling the business administration that prevents you from spending your full working day doing what you do best: creating beautiful things from timber.',
  'Carpentry businesses that grow beyond sole trader level face an administrative inflection point. Managing three or four simultaneous bespoke commissions, each with different material requirements, client communication expectations, and delivery timelines, creates coordination complexity that memory and notebooks cannot handle reliably. AI automation provides the intelligent business management layer that enables growth without sacrificing craft quality or personal time.',
  'We implement AI automation designed for the bespoke commission workflow. Enquiry processing categorises and prioritises incoming messages intelligently. Material procurement is tracked with species-specific lead times for exotic timbers. Commission progress tracking triggers appropriate client communications. Post-installation follow-up maintains client relationships for future referrals.',
  '[{"title": "Multiple bespoke commissions creating coordination complexity", "description": "Three simultaneous bespoke projects means three different timber orders, three client communication schedules, three installation timelines, and three invoicing milestones. Keeping all of these coordinated in your head whilst also spending your days at the bench creates inevitable oversights. A client who was promised an update last week gets forgotten. A timber order for the next project is placed too late."}, {"title": "Exotic timber procurement with unpredictable lead times", "description": "Standard oak is readily available. But a client requesting European walnut, American cherry, or reclaimed elm faces lead times that vary from weeks to months depending on supplier availability. Without intelligent procurement tracking that accounts for species-specific lead times and supplier patterns, material delays cascade into project delays that damage client relationships."}, {"title": "Post-completion client relationships not maintained", "description": "You deliver a stunning bespoke piece, the client is delighted, and then you never contact them again. Six months later, their friend admires the furniture and asks who made it. If the client has to search for your details because you never stayed in touch, the referral may not happen. Without systematic follow-up, completed commissions generate far fewer referrals than they should."}]',
  '[{"title": "Intelligent enquiry processing and commission management", "description": "AI processes incoming enquiries, categorises them by project type and estimated value, and drafts initial responses tailored to the specific work requested. A bespoke staircase enquiry receives a different response to a kitchen fitting request. Commission progress is tracked with milestone reminders that keep you informed of what needs attention across all active projects."}, {"title": "Material procurement with species-specific lead time intelligence", "description": "AI tracks your timber requirements across all active commissions and alerts you to ordering windows based on species-specific lead times. Standard hardwoods are flagged for ordering at shorter lead times. Exotic or specified species trigger earlier procurement alerts. Supplier availability patterns inform ordering recommendations. Material delays are predicted and flagged before they impact project timelines."}, {"title": "Post-installation relationship management", "description": "After delivery and installation, AI manages a follow-up sequence: a check-in at two weeks, a care instructions reminder at three months, a seasonal timber care tip at appropriate times, and an anniversary message at one year. This maintains the client relationship and keeps your business top-of-mind when referral opportunities arise, turning every completed commission into an ongoing marketing asset."}]',
  '[{"question": "Can AI help manage multiple bespoke commissions simultaneously?", "answer": "Yes. Each commission is tracked with its own timeline, material requirements, milestone schedule, and client communication plan. AI provides a consolidated view of all active projects, highlighting what needs attention today, what procurement needs placing this week, and which clients are due an update. This coordination layer prevents the oversights that occur when managing multiple bespoke projects manually."}, {"question": "How does the timber procurement intelligence work?", "answer": "You specify the timber species required for each commission. AI references lead time data for each species and your preferred suppliers, calculating when orders need placing to arrive in time for your workshop schedule. Standard hardwoods might need two weeks. Specified exotic species might need eight weeks. The system alerts you at the appropriate time for each, preventing material-related project delays."}, {"question": "Will AI draft my client communications?", "answer": "Yes. AI drafts progress updates, milestone notifications, and follow-up messages based on the current stage of each commission. A client whose bookcase has entered the finishing stage receives a draft update referencing that milestone specifically. You review, personalise if needed, and send. The drafting time saved across multiple clients is significant."}, {"question": "How does the post-installation follow-up work?", "answer": "After a project is completed and marked as delivered, AI schedules a sequence of follow-up touchpoints. An initial satisfaction check at two weeks, a timber care reminder, seasonal maintenance tips relevant to the timber species used, and a one-year anniversary message. Each communication is branded and referenced to the specific piece you created, maintaining a personal, craft-focused relationship."}]'
)
